}

// Div performs division on same-type operands only.
// int/int→int, float/float→float.
func Div(a, b Value) Value {
	switch a := a.(type) {
	case *Int:
		if b, ok := b.(*Int); ok {
			if b.Val == 0 {
				panic("Hiss! Division by zero, nya~")
			}
			return NewInt(a.Val / b.Val)
		}
	case *Byte:
		if b, ok := b.(*Byte); ok {
			if b.Val == 0 {
