// expectPanic now verifies that the operator returns a Furball whose Message
// contains the expected substring. The name is kept for minimal test churn
// after the panic-to-Furball migration.
func expectPanic(t *testing.T, msg string, fn func()) {
	t.Helper()
	expectFurball(t, msg, fn)
}

// expectFurball runs fn (which must call a single operator returning Value)
// and verifies the result is a Furball containing the expected message.
// Operator calls inside fn are captured via a package-level slot.
func expectFurball(t *testing.T, msg string, fn func()) {
	t.Helper()
	lastFurballResult = nil
	fn()
	if lastFurballResult == nil {
		t.Fatalf("expected a Furball result containing %q, but operator returned a value", msg)
	}
	if !strings.Contains(lastFurballResult.Message, msg) {
		t.Fatalf("Furball message %q does not contain %q", lastFurballResult.Message, msg)
	}
}

// lastFurballResult holds the most recent Furball captured by check().
var lastFurballResult *Furball

// check captures any Furball returned by an operator so expectFurball can
// inspect it. Returns the value unchanged for chaining.
func check(v Value) Value {
	if f, ok := v.(*Furball); ok {
