	if err != nil {
		return furball(err)
	}
	if ct != "" {
		req.Header.Set("Content-Type", ct)
	}
	applyHeaders(req, opts)

	resp, err := client.Do(req)
	if err != nil {
		return furball(err)
	}
	defer resp.Body.Close()
	v, err := readResponse(resp, opts.maxBodyBytes)
	if err != nil {
		return furball(err)
	}
