1	package meowtest
2	
3	import (
4		"bytes"
5		"fmt"
6		"io"
7		"os"
8	
9		"github.com/135yshr/meow/runtime/meowrt"
10	)
11	
12	// testFailure is a panic value used by test assertions.
13	// Distinct from Hiss! panics so Run can differentiate.
14	type testFailure struct {
15		message string
16	}
17	
18	type testResult struct {
19		name   string
20		passed bool
21		msg    string
22	}
23	
24	var (
25		output  io.Writer = os.Stdout
26		results []testResult
27		exitFn  = func(code int) { os.Exit(code) }
28	)
29	
30	// Reset clears accumulated test results and reconfigures output/exit.
31	func Reset(w io.Writer, exit func(int)) {
32		results = nil
33		if w != nil {
34			output = w
35		} else {
36			output = os.Stdout
37		}
38		if exit != nil {
39			exitFn = exit
40		} else {
41			exitFn = func(code int) { os.Exit(code) }
42		}
43	}
44	
45	// Judge asserts that a condition is truthy.
46	// Usage: judge(condition) or judge(condition, "message")
47	func Judge(args ...meowrt.Value) meowrt.Value {
48		if len(args) < 1 {
49			panic("Hiss! judge expects at least 1 argument, nya~")
50		}
51		if !args[0].IsTruthy() {
52			msg := "assertion failed: expected truthy value"
53			if len(args) >= 2 {
54				msg = args[1].String()
55			}
56			panic(testFailure{message: msg})
57		}
58		return meowrt.NewNil()
59	}
60	
61	// Expect asserts that two values are equal (by String representation).
62	// Usage: expect(actual, expected) or expect(actual, expected, "message")
63	func Expect(args ...meowrt.Value) meowrt.Value {
64		if len(args) < 2 {
65			panic("Hiss! expect expects at least 2 arguments, nya~")
66		}
67		actual := args[0]
68		expected := args[1]
69		if actual.String() != expected.String() {
70			msg := fmt.Sprintf("expected %s, got %s", expected.String(), actual.String())
71			if len(args) >= 3 {
72				msg = fmt.Sprintf("%s: expected %s, got %s", args[2].String(), expected.String(), actual.String())
73			}
74			panic(testFailure{message: msg})
75		}
76		return meowrt.NewNil()
77	}
78	
79	// Refuse asserts that a condition is falsy.
80	// Usage: refuse(condition) or refuse(condition, "message")
81	func Refuse(args ...meowrt.Value) meowrt.Value {
82		if len(args) < 1 {
83			panic("Hiss! refuse expects at least 1 argument, nya~")
84		}
85		if args[0].IsTruthy() {
86			msg := "assertion failed: expected falsy value"
87			if len(args) >= 2 {
88				msg = args[1].String()
89			}
90			panic(testFailure{message: msg})
91		}
92		return meowrt.NewNil()
93	}
94	
95	// Run executes a named test function, catching panics, and records the result.
96	// Usage: run("test name", fn)
97	func Run(args ...meowrt.Value) meowrt.Value {
98		if len(args) < 2 {
99			panic("Hiss! run expects 2 arguments (name, fn), nya~")
100		}
101		name, ok := args[0].(*meowrt.String)
102		if !ok {
103			panic(fmt.Sprintf("Hiss! run expects a String name, got %s, nya~", args[0].Type()))
104		}
105		fn, ok := args[1].(*meowrt.Func)
106		if !ok {
107			panic(fmt.Sprintf("Hiss! run expects a Func, got %s, nya~", args[1].Type()))
108		}
109	
110		passed := true
111		var msg string
112		func() {
113			defer func() {
114				if r := recover(); r != nil {
115					passed = false
116					if tf, ok := r.(testFailure); ok {
117						msg = tf.message
118					} else {
119						msg = fmt.Sprintf("%v", r)
120					}
121				}
122			}()
123			fn.Call()
124		}()
125	
126		status := "PASS"
127		if !passed {
128			status = "FAIL"
129		}
130		fmt.Fprintf(output, "  %s: %s", status, name.Val)
131		if msg != "" {
132			fmt.Fprintf(output, " - %s", msg)
133		}
134		fmt.Fprintln(output)
135	
136		results = append(results, testResult{name: name.Val, passed: passed, msg: msg})
137		return meowrt.NewBool(passed)
138	}
139	
140	// Catwalk executes a named function, captures its stdout output, and compares
141	// it with the expected output string. This is the Meow equivalent of Go's
142	// Example tests with // Output: comments.
143	// Usage: Catwalk(name, fn, expected)
144	func Catwalk(args ...meowrt.Value) meowrt.Value {
145		if len(args) < 3 {
146			panic("Hiss! catwalk expects 3 arguments (name, fn, expected), nya~")
147		}
148		name, ok := args[0].(*meowrt.String)
149		if !ok {
150			panic(fmt.Sprintf("Hiss! catwalk expects a String name, got %s, nya~", args[0].Type()))
151		}
152		fn, ok := args[1].(*meowrt.Func)
153		if !ok {
154			panic(fmt.Sprintf("Hiss! catwalk expects a Func, got %s, nya~", args[1].Type()))
155		}
156		expected, ok := args[2].(*meowrt.String)
157		if !ok {
158			panic(fmt.Sprintf("Hiss! catwalk expects a String expected, got %s, nya~", args[2].Type()))
159		}
160	
161		// Capture stdout using os.Pipe.
162		oldStdout := os.Stdout
163		r, w, err := os.Pipe()
164		if err != nil {
165			panic(fmt.Sprintf("Hiss! cannot create pipe, nya~: %v", err))
166		}
167		os.Stdout = w
168	
169		// Read pipe output in a goroutine to prevent deadlock.
170		captured := make(chan string)
171		go func() {
172			var buf bytes.Buffer
173			buf.ReadFrom(r)
174			captured <- buf.String()
175		}()
176	
177		passed := true
178		var msg string
179		func() {
180			defer func() {
181				if rec := recover(); rec != nil {
182					passed = false
183					if tf, ok := rec.(testFailure); ok {
184						msg = tf.message
185					} else {
186						msg = fmt.Sprintf("panic: %v", rec)
187					}
188				}
189			}()
190			fn.Call()
191		}()
192	
193		// Close writer and restore stdout.
194		w.Close()
195		os.Stdout = oldStdout
196		got := <-captured
197		r.Close()
198	
199		// Compare output if function didn't panic.
200		if passed && got != expected.Val {
201			passed = false
202			msg = fmt.Sprintf("output mismatch:\ngot:\n%swant:\n%s", got, expected.Val)
203		}
204	
205		status := "PASS"
206		if !passed {
207			status = "FAIL"
208		}
209		fmt.Fprintf(output, "  %s: %s", status, name.Val)
210		if msg != "" {
211			fmt.Fprintf(output, " - %s", msg)
212		}
213		fmt.Fprintln(output)
214	
215		results = append(results, testResult{name: name.Val, passed: passed, msg: msg})
216		return meowrt.NewBool(passed)
217	}
218	
219	// Report outputs the test summary. Calls os.Exit(1) if any test failed.
220	func Report(args ...meowrt.Value) meowrt.Value {
221		passed := 0
222		failed := 0
223		for _, r := range results {
224			if r.passed {
225				passed++
226			} else {
227				failed++
228			}
229		}
230	
231		fmt.Fprintln(output)
232		if failed == 0 {
233			fmt.Fprintf(output, "All %d tests passed, nya~!\n", passed)
234		} else {
235			fmt.Fprintf(output, "%d passed, %d failed, nya~\n", passed, failed)
236		}
237	
238		if failed > 0 {
