// Gag calls fn (a zero-argument Func) and returns its result.
// Untyped Meow code propagates errors as Furball values, so the result is
// returned directly. Typed Meow functions may still panic internally
// (hiss inside a typed body), so a deferred recover converts those panics
// into a Furball. This dual handling is the bridge between the value-based
// (untyped) and panic-based (typed-optimization) paths.
func Gag(fn Value) (result Value) {
	if f, ok := fn.(*Furball); ok {
		return f
	}
	f, ok := fn.(*Func)
	if !ok {
		return &Furball{Message: fmt.Sprintf("Hiss! gag expects a function, got %s, nya~", fn.Type())}
	}
	defer func() {
		if r := recover(); r != nil {
			result = &Furball{Message: fmt.Sprintf("%v", r)}
		}
	}()
	return f.Call()
}

